const outputMessage = $json.output;

// Formata a mensagem com quebras de linha e emojis
const formattedMessage = `${outputMessage}`;

// Retorno formatado para o webhook
return [
  {
    json: {
      message: formattedMessage,
    }
  }
];

// n8n Code node (JavaScript)
const inputs = $input.all();
const allCalendars = [];

for (const item of inputs) {
  const data = item.json;
  const entries = Array.isArray(data?.items) ? data.items : [];

  for (const e of entries) {
    // Pula a agenda "Holidays in Brazil"
    if (e.id === "en.brazilian#holiday@group.v.calendar.google.com") {
      continue;
    }

    allCalendars.push({
      "Calendar Name": e.summary ?? "N/A",
      "Calendar ID": e.id ?? "N/A",
      "Time Zone": e.timeZone ?? "N/A",
      "Access Role": e.accessRole ?? "N/A",
      "Conference Allowed": Array.isArray(e?.conferenceProperties?.allowedConferenceSolutionTypes)
        ? e.conferenceProperties.allowedConferenceSolutionTypes.join(", ")
        : "None",
      "Color": e.backgroundColor ?? "#FFFFFF",
      "Default Reminders": Array.isArray(e.defaultReminders) && e.defaultReminders.length
        ? e.defaultReminders.map(r => `${r.method || "popup"} in ${r.minutes} minutes`).join(", ")
        : "No Reminders",
      "Primary Calendar": e.primary ? "Yes" : "No",
      "Selected": e.selected ? "Yes" : "No",
    });
  }
}

return [
  {
    json: {
      count: allCalendars.length,
      calendars: allCalendars,
    },
  },
];

// n8n Code node â€” Run Once for All Items

function getPayloadFromItems(items) {
  // Caso 1: um Ãºnico item cujo json Ã© o array bruto
  if (items.length === 1 && Array.isArray(items[0].json)) {
    return items[0].json;
  }

  // Caso 2: um Ãºnico item com o array em json.payload
  if (items.length === 1 && Array.isArray(items[0].json?.payload)) {
    return items[0].json.payload;
  }

  // Caso 3: mÃºltiplos itens, cada um jÃ¡ no formato { data, message: {...} }
  if (items.length > 1 && items.every(i => i.json && i.json.message && i.json.data)) {
    return items.map(i => i.json);
  }

  // Caso 4: um Ãºnico item jÃ¡ no formato { data, message: {...} }
  if (items.length === 1 && items[0].json?.message && items[0].json?.data) {
    return [items[0].json];
  }

  throw new Error('Formato inesperado. Envie: (a) 1 item com um array no `json`, ou (b) 1 item com `json.payload` sendo array, ou (c) mÃºltiplos itens com `json.data` e `json.message`.');
}

const payload = getPayloadFromItems(items);

const mensagens = payload.map(item => ({
  data: item.data,
  enviadoPor: item.message?.type === 'ai' ? 'IA' : 'Human',
  mensagem: item.message?.content ?? ''
}));

return [
  {
    json: { mensagens }
  }
];

