// Gera 1 item por calendar_id mantendo as datas exatamente como vieram
const inputItems = $input.all();
const out = [];

for (const { json } of inputItems) {
  // Suporta payloads com body ou direto na raiz
  const body = json.body ?? json;

  // Normaliza calendar_ids (array ou string)
  let ids = body.calendar_ids ?? [];
  if (typeof ids === 'string') ids = [ids];
  if (!Array.isArray(ids)) ids = [];

  const data_inicial = body.data_inicial ?? json.data_inicial ?? null;
  const data_final   = body.data_final   ?? json.data_final   ?? null;

  for (const calendar_id of ids) {
    out.push({
      json: {
        calendar_id,
        data_inicial,
        data_final,
        // opcional: repasso alguns campos Ãºteis se vocÃª quiser usar depois
        tipo_busca: body.tipo_busca ?? null,
        mes: body.mes ?? null,
        ano: body.ano ?? null,
        periodo: body.periodo ?? null
      }
    });
  }
}

return out;

